  return 1; } } while(0)

// Read-only streaming kernel. Grid-stride loop over float4 elements,
// accumulate, and conditionally write to a sink so the compiler cannot
// eliminate the loads.
__global__ void streamRead(const float4* __restrict__ in, size_t n4, float* sink) {
    size_t idx = (size_t)blockIdx.x * blockDim.x + threadIdx.x;
    size_t stride = (size_t)gridDim.x * blockDim.x;
    float4 acc = make_float4(0.f, 0.f, 0.f, 0.f);
    for (size_t i = idx; i < n4; i += stride) {
        float4 v = in[i];
        acc.x += v.x; acc.y += v.y; acc.z += v.z; acc.w += v.w;
    }
    float s = acc.x + acc.y + acc.z + acc.w;
    // Effectively never taken; keeps `acc` live.
    if (s == -1.0f) sink[idx] = s;
}

int main(int argc, char** argv) {
    // ~4 GiB working set.
    size_t bytes = (size_t)4 * 1024 * 1024 * 1024;
    if (argc > 1) bytes = (size_t)atoll(argv[1]);
    size_t n4 = bytes / sizeof(float4);
    bytes = n4 * sizeof(float4); // exact bytes read in one pass

    float4* d_in = nullptr;
    float* d_sink = nullptr;
    CHECK(hipMalloc(&d_in, bytes));
    CHECK(hipMalloc(&d_sink, 1024 * sizeof(float)));
    CHECK(hipMemset(d_in, 1, bytes));
    CHECK(hipMemset(d_sink, 0, 1024 * sizeof(float)));

    int dev; CHECK(hipGetDevice(&dev));
    hipDeviceProp_t prop; CHECK(hipGetDeviceProperties(&prop, dev));

    int threads = 256;
    // Saturate: many blocks per CU.
    int blocks = prop.multiProcessorCount * 32;

    // Warmup
    for (int i = 0; i < 5; ++i)
        hipLaunchKernelGGL(streamRead, dim3(blocks), dim3(threads), 0, 0, d_in, n4, d_sink);
    CHECK(hipDeviceSynchronize());

    const int iters = 50;
    std::vector<float> times;
    hipEvent_t start, stop;
    CHECK(hipEventCreate(&start));
    CHECK(hipEventCreate(&stop));

    for (int i = 0; i < iters; ++i) {
        CHECK(hipEventRecord(start));
        hipLaunchKernelGGL(streamRead, dim3(blocks), dim3(threads), 0, 0, d_in, n4, d_sink);
        CHECK(hipEventRecord(stop));
        CHECK(hipEventSynchronize(stop));
        float ms = 0.f;
        CHECK(hipEventElapsedTime(&ms, start, stop));
        times.push_back(ms);
    }

    std::sort(times.begin(), times.end());
    float median_ms = times[times.size() / 2];
    double gbps = (double)bytes / (median_ms * 1e-3) / 1e9;

    printf("HBM_BANDWIDTH_GBPS=%.2f\n", gbps);
    printf("buffer_bytes=%zu\n", bytes);

    hipFree(d_in);
    hipFree(d_sink);
    return 0;
